class Solution {
    private static final int MOD = 1_000_000_007;

    public int numberOfWays(int n, int x, int y) {
        int max = Math.max(n, x);
        long[] fact = new long[max + 1];
        long[] invFact = new long[max + 1];
        fact[0] = 1;
        for (int i = 1; i <= max; i++) {
            fact[i] = fact[i - 1] * i % MOD;
        }
        invFact[max] = pow(fact[max], MOD - 2);
        for (int i = max - 1; i >= 0; i--) {
            invFact[i] = invFact[i + 1] * (i + 1) % MOD;
        }

        long ans = 0;
        long powY = 1;
        long powX = 1;
        for (int k = 1; k <= Math.min(n, x); k++) {
            powY = powY * y % MOD;
            long c = fact[x] * invFact[x - k] % MOD;
            long s = stirling(n, k, fact, invFact);
            ans = (ans + c * s % MOD * powY) % MOD;
        }
        return (int) ans;
    }

    private long stirling(int n, int k, long[] fact, long[] invFact) {
        long res = 0;
        for (int j = 0; j <= k; j++) {
            long sign = (j & 1) == 0 ? 1 : -1;
            long term = fact[k] * invFact[j] % MOD * invFact[k - j] % MOD;
            term = term * pow(j, n) % MOD;
            res = (res + sign * term + MOD) % MOD;
        }
        return res;
    }

    private long pow(long a, int b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = res * a % MOD;
            a = a * a % MOD;
            b >>= 1;
        }
        return res;
    }
}
